import{_ as e,c as l,o as r,ah as o}from"./chunks/framework.Cnj7lwEt.js";const g=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/Deno-开发工具.md","filePath":"github汇总/开发工具/Deno-开发工具.md"}'),n={name:"github汇总/开发工具/Deno-开发工具.md"};function i(t,a,s,h,d,c){return r(),l("div",null,a[0]||(a[0]=[o('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Deno</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Deno Land</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>Node.js依赖管理复杂、安全问题、开发体验不佳、缺少内置TypeScript支持</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>安全默认设置</li><li>内置TypeScript支持</li><li>内置标准库</li><li>内置依赖管理</li><li>内置测试工具</li><li>不需要npm，直接从URL导入模块</li><li>基于V8、Rust和Tokio构建</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>由Node.js创始人Ryan Dahl开发</li><li>安全默认设置，更安全</li><li>内置TypeScript支持，无需额外配置</li><li>不需要npm，直接从URL导入</li><li>内置丰富工具，开箱即用</li><li>现代JavaScript运行时</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/denoland/deno" target="_blank" rel="noreferrer">https://github.com/denoland/deno</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于想要使用Deno运行JavaScript和TypeScript的开发者，支持Windows、macOS、Linux。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：Windows 10及以上、macOS 10.15及以上、主流Linux发行版</li><li>网络要求：能够访问Deno官方下载站点</li></ol><h2 id="主路径-快速安装-推荐新手" tabindex="-1">主路径：快速安装（推荐新手） <a class="header-anchor" href="#主路径-快速安装-推荐新手" aria-label="Permalink to “主路径：快速安装（推荐新手）”">​</a></h2><h3 id="步骤1-安装deno" tabindex="-1">步骤1：安装Deno <a class="header-anchor" href="#步骤1-安装deno" aria-label="Permalink to “步骤1：安装Deno”">​</a></h3><p><strong>步骤目标</strong>：在系统上安装Deno <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：</p><ul><li>Windows (PowerShell)：运行 <code>irm https://deno.land/install.ps1 | iex</code></li><li>macOS/Linux (Shell)：运行 <code>curl -fsSL https://deno.land/install.sh | sh</code></li><li>Homebrew (macOS)：运行 <code>brew install deno</code></li><li>Chocolatey (Windows)：运行 <code>choco install deno</code><strong>成功标志</strong>：安装完成提示 <strong>失败处理</strong>：检查网络连接，或参考 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><h3 id="步骤2-验证安装" tabindex="-1">步骤2：验证安装 <a class="header-anchor" href="#步骤2-验证安装" aria-label="Permalink to “步骤2：验证安装”">​</a></h3><p><strong>步骤目标</strong>：确认Deno安装成功 <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：运行 <code>deno --version</code><strong>成功标志</strong>：显示Deno版本号 <strong>失败处理</strong>：检查环境变量PATH是否配置</p><h3 id="步骤3-运行第一个程序" tabindex="-1">步骤3：运行第一个程序 <a class="header-anchor" href="#步骤3-运行第一个程序" aria-label="Permalink to “步骤3：运行第一个程序”">​</a></h3><p><strong>步骤目标</strong>：创建并运行一个简单的Deno程序 <strong>执行位置</strong>：命令行终端和代码编辑器 <strong>完整命令或操作</strong>：</p><ol><li>创建server.ts文件，写入示例代码</li><li>运行 <code>deno run --allow-net server.ts</code><strong>成功标志</strong>：服务器启动成功，访问http://localhost:8000显示Hello, world! <strong>失败处理</strong>：检查代码语法，确认端口未被占用</li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><p>运行 <code>deno --version</code> 显示版本信息，运行示例服务器成功。</p><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象</strong>：命令行找不到deno命令</p><ul><li><strong>可能原因</strong>：环境变量PATH未配置</li><li><strong>解决步骤</strong>：将Deno的bin目录添加到系统PATH环境变量</li></ul></li><li><p><strong>现象</strong>：网络安装失败</p><ul><li><strong>可能原因</strong>：网络问题</li><li><strong>解决步骤</strong>：参考 <a href="/网络环境.html">海外网络环境配置 →</a>，或使用其他安装方式</li></ul></li><li><p><strong>现象</strong>：权限被拒绝</p><ul><li><strong>可能原因</strong>：Deno安全默认设置</li><li><strong>解决步骤</strong>：使用正确的权限标志，如--allow-net、--allow-read等</li></ul></li></ol><h2 id="备选部署路径-从源码构建" tabindex="-1">备选部署路径：从源码构建 <a class="header-anchor" href="#备选部署路径-从源码构建" aria-label="Permalink to “备选部署路径：从源码构建”">​</a></h2><p>如二进制安装包不适用，可参考官方文档从源码构建。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>无缺失，README提供了完整的安装指引。</p>',38)]))}const b=e(n,[["render",i]]);export{g as __pageData,b as default};
